// quiz-linguistics.js — Comprehensive Linguistics Question Bank (sections ling1–ling12)
window.quizLinguistics = [

  // ── LING1: Foundations — Saussure & Chomsky ──────────────────────────────
  { section:"ling1", q:"Who is considered the 'Father of Modern Linguistics'?", options:["Noam Chomsky","Ferdinand de Saussure","B.F. Skinner"], correct:1, explanation:"Saussure (1857-1913) revolutionized the field by studying language as a structured system of signs at a given point in time." },
  { section:"ling1", q:"According to Saussure, what is the 'Signifier'?", options:["The mental concept or idea","The physical sound-image or written form","The grammar rules of a language"], correct:1, explanation:"The Signifier is the 'form' (the sound or the written letters), while the Signified is the 'concept' it represents." },
  { section:"ling1", q:"According to Saussure, what is the 'Signified'?", options:["The physical sound or written word","The mental concept or idea triggered by the signifier","The actual object in the real world"], correct:1, explanation:"The Signified is the mental concept. For example, hearing the word 'cat' triggers the mental image of a cat." },
  { section:"ling1", q:"What does Saussure mean by the 'Arbitrariness of the Sign'?", options:["Signs are chosen randomly by individuals","There is no natural or logical link between the signifier and the signified","All languages share the same signs"], correct:1, explanation:"The word 'tree' doesn't sound like a tree; it's a social convention. Different languages use different sounds for the same concept." },
  { section:"ling1", q:"What is 'Langue' according to Saussure?", options:["An individual's specific speech act","The abstract, collective system of language rules shared by a community","A type of grammar rule"], correct:1, explanation:"Langue is the abstract system of rules (like the rules of chess), whereas Parole is the actual use of that system (the specific game played)." },
  { section:"ling1", q:"What is 'Parole' according to Saussure?", options:["The abstract language system","An individual's actual speech acts in specific contexts","A language family"], correct:1, explanation:"Parole refers to the concrete instances of language use by individuals in specific situations." },
  { section:"ling1", q:"What is 'Universal Grammar' (UG) according to Chomsky?", options:["Humans are born with an innate language template/blueprint","All languages use the exact same vocabulary","Language is learned entirely through social conditioning"], correct:0, explanation:"Chomsky argues that humans have a biological predisposition to learn language, containing the basic structural principles of all human languages." },
  { section:"ling1", q:"What is the 'Language Acquisition Device' (LAD)?", options:["A software for learning languages","An innate mental module that allows children to extract language rules from their environment","A type of dictionary used by linguists"], correct:1, explanation:"The LAD is a hypothetical 'black box' in the brain that explains how children learn complex grammar so quickly without formal instruction." },
  { section:"ling1", q:"What does Chomsky mean by 'Competence'?", options:["How fast a person can speak","A speaker's internalized, unconscious knowledge of language rules","The actual sentences produced in conversation"], correct:1, explanation:"Competence is the perfect knowledge of a language's grammar that a native speaker possesses internally." },
  { section:"ling1", q:"What does Chomsky mean by 'Performance'?", options:["A speaker's underlying knowledge","The actual use of language in real situations, including errors and slips","The ability to perform a play"], correct:1, explanation:"Performance is how we actually use language, which can be affected by tiredness, memory lapses, or distractions." },
  { section:"ling1", q:"Which philosopher/linguist is associated with 'Behaviorism'?", options:["Saussure","Chomsky","B.F. Skinner"], correct:2, explanation:"Skinner believed language is a behavior learned through imitation and reinforcement (reward/punishment)." },
  { section:"ling1", q:"What is 'Poverty of the Stimulus'?", options:["The idea that poor people have smaller vocabularies","Chomsky's argument that children aren't exposed to enough data to learn complex grammar by imitation alone","A lack of educational resources"], correct:1, explanation:"This is a key argument for nativism—children know things about language that they couldn't have learned from just listening to adults." },
  { section:"ling1", q:"What is 'Synchronic' linguistics?", options:["Studying language change over long periods of time","Studying a language system as it exists at a single point in time","The study of synchronized speech"], correct:1, explanation:"Saussure favored synchronic study (a snapshot) over diachronic study (historical progression)." },
  { section:"ling1", q:"What is 'Diachronic' linguistics?", options:["Studying language at one point in time","Studying language evolution and change over time","The study of two languages at once"], correct:1, explanation:"Diachronic linguistics looks at how words and grammar change from one century to the next." },
  { section:"ling1", q:"What is the 'Syntagmatic' relationship?", options:["Vertical relationship (substitution)","Horizontal relationship (linear sequence of words in a sentence)","Meaning-based relationship"], correct:1, explanation:"Syntagmatic relations are about how words combine in a chain (e.g., 'The' + 'cat' + 'sat')." },
  { section:"ling1", q:"What is the 'Paradigmatic' relationship?", options:["Vertical relationship where one word can be swapped for another of the same category","Horizontal relationship of words in a sentence","A type of vowel shift"], correct:0, explanation:"Paradigmatic relations are about the choices you have at a specific point in a sentence (e.g., swapping 'cat' for 'dog')." },
  { section:"ling1", q:"Saussure compared Langue and Parole to what game?", options:["Football","Chess","Cards"], correct:1, explanation:"The rules of chess = Langue; the actual game being played = Parole. You can break Parole rules (blunder) but not Langue rules (you can't play without knowing them)." },
  { section:"ling1", q:"What is 'Structural Linguistics'?", options:["Studying the physical structure of the throat","Analyzing language as a self-contained system of interrelated units","The study of grammar books"], correct:1, explanation:"Saussure founded this approach — language is studied as a system where each element gets its value from its difference from other elements." },
  { section:"ling1", q:"What are 'Transformational Rules' in Chomsky's theory?", options:["Rules that translate words between languages","Operations that convert deep structure into surface structure","Rules for changing accents"], correct:1, explanation:"For example, a transformation converts an active sentence into its passive equivalent." },
  { section:"ling1", q:"Chomsky argued against Skinner's behaviorism mainly by pointing out what?", options:["Children make no errors when learning language","Children can produce and understand sentences they have never heard before","Language is only learned in school"], correct:1, explanation:"This 'creativity' of language cannot be explained by simple imitation and reinforcement." },
  { section:"ling1", q:"What is a 'Linguistic Sign' according to Saussure?", options:["A road sign in a foreign language","The union of a Signifier and a Signified","A word borrowed from another language"], correct:1, explanation:"The sign is the whole unit (the sound-image + the concept), not just the word itself." },
  { section:"ling1", q:"What is the 'Critical Period Hypothesis'?", options:["The idea that language must be learned before puberty for full native-like acquisition","The best time to teach reading","A critical analysis of language change"], correct:0, explanation:"After puberty, acquiring a first language becomes increasingly difficult. Evidence comes from 'feral children' like Genie." },
  { section:"ling1", q:"Who proposed the 'Critical Period Hypothesis'?", options:["Saussure","Lenneberg","Skinner"], correct:1, explanation:"Eric Lenneberg (1967) proposed this biological timeline for language acquisition." },
  { section:"ling1", q:"What does 'Nativism' claim about language?", options:["Language is entirely culturally transmitted","Humans are biologically pre-programmed to acquire language","Language is a skill like riding a bike"], correct:1, explanation:"Nativism (associated with Chomsky) holds that we are born with innate knowledge of universal linguistic principles." },

  // ── LING2: Phonetics ─────────────────────────────────────────────────────
  { section:"ling2", q:"What is Phonetics?", options:["The study of meaning","The scientific study of the production, transmission, and perception of speech sounds","The study of writing"], correct:1, explanation:"Phonetics deals with the raw physical sounds of human speech, regardless of which language they belong to." },
  { section:"ling2", q:"What are the three branches of Phonetics?", options:["Phonology, Morphology, Syntax","Articulatory, Acoustic, and Auditory Phonetics","Vowels, Consonants, and Diphthongs"], correct:1, explanation:"Articulatory (how sounds are made), Acoustic (sound waves), and Auditory (how we hear them)." },
  { section:"ling2", q:"Which IPA symbol represents a 'Voiced Bilabial Plosive'?", options:["/p/","/b/","/m/"], correct:1, explanation:"/b/ is voiced (vibrating cords), bilabial (both lips), and a plosive (stop)." },
  { section:"ling2", q:"What is an 'Alveolar' sound?", options:["Sound made with the back of the tongue","Sound made with the tongue tip at the bony ridge behind the upper teeth","Sound made in the throat"], correct:1, explanation:"Sounds like /t/, /d/, /s/, /z/, /n/, and /l/ are alveolar in English." },
  { section:"ling2", q:"Which of these is a 'Velar' sound?", options:["/p/","/t/","/k/"], correct:2, explanation:"/k/ and /g/ are velar because the back of the tongue touches the soft palate (velum)." },
  { section:"ling2", q:"What defines a 'Fricative'?", options:["A total blockage of air","Air is forced through a narrow opening, creating a hissing sound","Air passes through the nose"], correct:1, explanation:"Sounds like /f/, /v/, /s/, /z/, and /h/ are fricatives." },
  { section:"ling2", q:"What is an 'Affricate'?", options:["A combination of a stop and a fricative","A sound made with three lips","A type of vowel"], correct:0, explanation:"/tʃ/ (church) and /dʒ/ (judge) are affricates." },
  { section:"ling2", q:"What is a 'Nasal' sound?", options:["Sound made with a blocked nose","Sound made while the soft palate is lowered, letting air escape through the nose","A high-pitched sound"], correct:1, explanation:"/m/, /n/, and /ŋ/ (sing) are nasal sounds." },
  { section:"ling2", q:"What is the 'Glottis'?", options:["The back of the tongue","The opening between the vocal cords in the larynx","The roof of the mouth"], correct:1, explanation:"The glottis is where voicing is controlled and where the 'glottal stop' /ʔ/ is produced." },
  { section:"ling2", q:"What is a 'Diphthong'?", options:["A long consonant","A single syllable containing a glide between two vowel positions","A word with two meanings"], correct:1, explanation:"Examples include /aɪ/ in 'buy' and /aʊ/ in 'cow'." },
  { section:"ling2", q:"What does 'Voiced' mean in phonetics?", options:["The sound is very loud","The vocal cords vibrate when the sound is produced","The sound is made with the lips"], correct:1, explanation:"Compare /s/ (voiceless) and /z/ (voiced) — place your finger on your throat and feel the buzz for /z/." },
  { section:"ling2", q:"What is a 'Bilabial' sound?", options:["A sound made with the tongue","A sound produced using both lips","A sound made in the throat"], correct:1, explanation:"/p/, /b/, and /m/ are all bilabial sounds." },
  { section:"ling2", q:"What is a 'Lateral' sound?", options:["A sound made at the side of the mouth","Air flows around the sides of the tongue (e.g., /l/)","A sound made with lateral breathing"], correct:1, explanation:"/l/ is the main lateral in English — air flows along the sides of the tongue, not the center." },
  { section:"ling2", q:"What is a 'Trill'?", options:["A sound made by vibrating the tongue or lips rapidly","A very high-pitched vowel","A type of diphthong"], correct:0, explanation:"The Spanish 'rr' is a classic trill. English doesn't have trills, but they exist in many other languages." },
  { section:"ling2", q:"What is 'Aspiration' in phonetics?", options:["Breathing through the mouth","A puff of air that follows a voiceless stop (like the /p/ in 'pin')","A type of nasal sound"], correct:1, explanation:"In English, 'pin' has an aspirated /pʰ/, but 'spin' does not." },
  { section:"ling2", q:"What is 'Articulation'?", options:["The ability to speak clearly","The use of the vocal organs (lips, tongue, etc.) to produce speech sounds","A type of speech disorder"], correct:1, explanation:"Articulatory phonetics maps exactly which organs move to produce each sound." },
  { section:"ling2", q:"What does the IPA stand for?", options:["International Phonetic Alphabet","International Pronunciation Assessment","Indexed Phoneme Archive"], correct:0, explanation:"The IPA provides a standardized symbol for every speech sound in any human language." },
  { section:"ling2", q:"What is a 'Plosive' (Stop)?", options:["A sound where airflow is continuous","A sound where airflow is completely stopped and then released","A very soft sound"], correct:1, explanation:"/p/, /b/, /t/, /d/, /k/, /g/ are plosives in English." },
  { section:"ling2", q:"What is 'Acoustic Phonetics' concerned with?", options:["How we perceive sounds","The physical properties of sound waves as they travel through the air","How organs produce sounds"], correct:1, explanation:"Acoustic phonetics uses tools like spectrograms to measure frequency, amplitude, and duration of sounds." },
  { section:"ling2", q:"What is a 'Palatal' sound?", options:["A sound made with the palate and tongue blade","A sound that requires no tongue movement","A type of fricative only"], correct:0, explanation:"/j/ as in 'yes' is a palatal approximant — the tongue body rises toward the hard palate." },

  // ── LING3: Phonology ─────────────────────────────────────────────────────
  { section:"ling3", q:"What is Phonology?", options:["The study of physical speech sounds","The study of how sounds function and pattern within a specific language","The study of grammar"], correct:1, explanation:"Phonology is about the rules and systems of sounds in a language, whereas phonetics is the raw physical study." },
  { section:"ling3", q:"What is a 'Phoneme'?", options:["Any speech sound","The smallest unit of sound that can distinguish meaning in a language","A type of sentence"], correct:1, explanation:"Changing one phoneme changes the meaning of the word (e.g., /p/ to /b/ in 'pin' and 'bin')." },
  { section:"ling3", q:"What are 'Allophones'?", options:["Different languages","Variations of the same phoneme that do NOT change the meaning of a word","Opposite sounds"], correct:1, explanation:"The 'p' in 'pin' is aspirated, but the 'p' in 'spin' is not. Both are allophones of the phoneme /p/." },
  { section:"ling3", q:"What is a 'Minimal Pair'?", options:["Two words that rhyme","Two words that differ by exactly one sound and have different meanings","A pair of synonyms"], correct:1, explanation:"Minimal pairs like 'fan' and 'van' prove that /f/ and /v/ are distinct phonemes." },
  { section:"ling3", q:"What is 'Assimilation'?", options:["When a sound becomes more like a neighboring sound","When a sound disappears","When a sound is moved to the start of a word"], correct:0, explanation:"For example, 'in' + 'possible' becomes 'impossible' because /n/ changes to /m/ to match the bilabial /p/." },
  { section:"ling3", q:"What is 'Elision'?", options:["Adding a sound","The omission of a sound in fast or casual speech","Changing a vowel's pitch"], correct:1, explanation:"Example: pronouncing 'friendship' as 'fren-ship' (dropping the /d/)." },
  { section:"ling3", q:"What is 'Complementary Distribution'?", options:["Two phonemes that never appear in the same context","When two allophones never appear in the same phonetic environment, proving they're variants of the same phoneme","When two words share the same meaning"], correct:1, explanation:"Aspirated /pʰ/ appears at the start of stressed syllables; unaspirated /p/ appears after /s/. They never swap — complementary distribution." },
  { section:"ling3", q:"What is a 'Syllable'?", options:["A single letter","A unit of speech organized around a vowel (nucleus), with optional consonants before/after","A type of morpheme"], correct:1, explanation:"The syllable has three parts: Onset (initial consonants), Nucleus (vowel), and Coda (final consonants)." },
  { section:"ling3", q:"What is the 'Nucleus' of a syllable?", options:["The first consonant","The vowel (or syllabic consonant) at the center of the syllable","The last consonant"], correct:1, explanation:"The nucleus is the only obligatory part of a syllable — you can have a syllable with no onset and no coda, but not without a nucleus." },
  { section:"ling3", q:"What is 'Stress'?", options:["Feeling nervous while speaking","The relative emphasis given to a syllable in a word or sentence","A type of vowel change"], correct:1, explanation:"In 'photograph', stress falls on the first syllable: PHO-to-graph." },
  { section:"ling3", q:"What is 'Tone' in phonology?", options:["The emotion in speech","A phonemic use of pitch to distinguish word meaning","The loudness of speech"], correct:1, explanation:"In Mandarin Chinese, 'ma' with different tones means mother, hemp, horse, or scold." },
  { section:"ling3", q:"What is 'Intonation'?", options:["The rise and fall of pitch across an entire phrase or sentence","A single pitch change on one syllable","The same as tone"], correct:0, explanation:"English uses intonation to signal questions (rising) vs. statements (falling), not to distinguish word meanings." },
  { section:"ling3", q:"What is 'Phonotactics'?", options:["Military tactics for quiet movement","The rules governing which sound sequences are allowed in a language","A type of phoneme"], correct:1, explanation:"English allows 'str-' at the start of a word (street) but not 'bn-'. These are phonotactic constraints." },
  { section:"ling3", q:"What is 'Vowel Harmony'?", options:["Singing in tune","A phonological process where vowels in a word must share certain features (e.g., all front or all back)","Rhyming vowels"], correct:1, explanation:"Turkish is a classic example — suffixes change their vowels to match the vowel quality of the root." },
  { section:"ling3", q:"What is 'Metathesis'?", options:["A type of metaphor","The transposition of sounds within a word (e.g., 'ask' → 'aks' in some dialects)","Adding a vowel between consonants"], correct:1, explanation:"Historically, Old English 'brid' became modern 'bird' through metathesis." },

  // ── LING4: Morphology ────────────────────────────────────────────────────
  { section:"ling4", q:"What is Morphology?", options:["The study of sentences","The study of the internal structure of words and how they are formed","The study of meaning"], correct:1, explanation:"Morphology breaks words down into their smallest meaningful parts (morphemes)." },
  { section:"ling4", q:"What is a 'Morpheme'?", options:["A single letter","The smallest unit of meaning or grammatical function","A type of syllable"], correct:1, explanation:"Words can be made of one morpheme (cat) or many (un-happi-ness)." },
  { section:"ling4", q:"What is a 'Free Morpheme'?", options:["A morpheme that costs nothing","A morpheme that can stand alone as a complete word","A prefix or suffix"], correct:1, explanation:"Examples include 'dog', 'run', and 'the'." },
  { section:"ling4", q:"What is a 'Bound Morpheme'?", options:["A word that must be capitalized","A morpheme that must be attached to another morpheme (e.g., prefixes and suffixes)","A compound word"], correct:1, explanation:"Bound morphemes like 're-', 'un-', and '-ed' cannot exist as independent words." },
  { section:"ling4", q:"What is a 'Derivational' morpheme?", options:["It only adds grammatical information","It creates a new word or changes the word's grammatical category","It identifies the root of a word"], correct:1, explanation:"Adding '-ness' to 'happy' (adj) creates 'happiness' (noun). This is derivational." },
  { section:"ling4", q:"What is an 'Inflectional' morpheme?", options:["It creates a brand new word","It provides grammatical information (like tense or number) without changing the word's category","It is a type of prefix"], correct:1, explanation:"Adding '-s' to 'cat' makes 'cats'. It's still a noun; we just added plurality." },
  { section:"ling4", q:"How many inflectional suffixes are there in English?", options:["3","8","12"], correct:1, explanation:"They are: -s (plural), -'s (possessive), -s (3rd person singular), -ing (present participle), -ed (past tense), -en (past participle), -er (comparative), -est (superlative)." },
  { section:"ling4", q:"What is 'Compounding'?", options:["Shortening a word","Joining two or more free morphemes to form a new word","Borrowing a word from another language"], correct:1, explanation:"Examples: 'notebook', 'sunflower', 'textbook'." },
  { section:"ling4", q:"What is 'Blending'?", options:["Adding a suffix","Combining parts of two words to form a new one (e.g., smog = smoke + fog)","Repeating a word"], correct:1, explanation:"Blends involve 'clipping' the words first, like 'brunch' (breakfast + lunch)." },
  { section:"ling4", q:"What is 'Clipping'?", options:["Removing the middle of a word","Shortening a word without changing its meaning (e.g., 'ad' from 'advertisement')","Adding a prefix"], correct:1, explanation:"Other examples: 'prof' for professor, 'math' for mathematics." },
  { section:"ling4", q:"What is 'Acronym' formation?", options:["Adding letters to a word","Using the initial letters of a phrase to form a new word (e.g., NASA, SCUBA)","Borrowing a foreign word"], correct:1, explanation:"Acronyms are pronounced as a word (NASA), unlike abbreviations (FBI) which are spelled out." },
  { section:"ling4", q:"What is 'Back-formation'?", options:["Adding a suffix to an existing word","Creating a new word by removing a supposed suffix (e.g., 'edit' from 'editor')","Reversing a word"], correct:1, explanation:"People assumed 'editor' had the suffix '-or', so they back-formed 'edit'. Similarly: 'enthuse' from 'enthusiasm'." },
  { section:"ling4", q:"What is 'Conversion' (Zero Derivation)?", options:["Translating a word to another language","Changing a word's grammatical category without adding any morpheme (e.g., 'Google' → 'to Google')","A type of compounding"], correct:1, explanation:"Also called zero-derivation. 'Text' (noun) → 'to text' (verb). No suffix added." },
  { section:"ling4", q:"What is a 'Root' morpheme?", options:["A suffix that changes meaning","The core morpheme that carries the main lexical meaning of a word","A prefix added to the start"], correct:1, explanation:"In 'un-happi-ness', the root is 'happy' — the core meaning-carrying unit." },
  { section:"ling4", q:"What is 'Affixation'?", options:["The process of adding prefixes, suffixes, or infixes to a root word","Removing parts of a word","Combining two complete words"], correct:0, explanation:"Affixation is the most common word-formation process in English." },
  { section:"ling4", q:"What is an 'Infix'?", options:["A prefix","A suffix","A morpheme inserted inside a root word"], correct:2, explanation:"English rarely uses infixes, but informal examples include 'abso-blooming-lutely'. Tagalog uses infixes heavily." },
  { section:"ling4", q:"What is 'Reduplication'?", options:["Translating a word twice","Repeating all or part of a word to create a new form (e.g., 'goody-goody')","Using two synonyms"], correct:1, explanation:"Full reduplication (same word repeated) and partial reduplication (only part repeated) both exist across languages." },
  { section:"ling4", q:"What is a 'Portmanteau' word?", options:["A very long word","A blend where the meanings and parts of two words merge (e.g., 'Brexit' = British + Exit)","A loan word"], correct:1, explanation:"'Spork' (spoon + fork) is another classic portmanteau." },

  // ── LING5: Syntax ────────────────────────────────────────────────────────
  { section:"ling5", q:"What is Syntax?", options:["The study of word meaning","The study of the rules governing the arrangement of words into sentences","The study of speech sounds"], correct:1, explanation:"Syntax is basically the 'grammar' of sentence construction." },
  { section:"ling5", q:"What does 'S → NP VP' represent?", options:["A math formula","A Phrase Structure Rule (Sentence = Noun Phrase + Verb Phrase)","A phonetic transcription"], correct:1, explanation:"This is the most fundamental rule in English syntax." },
  { section:"ling5", q:"What is 'Deep Structure'?", options:["The actual words you hear","The underlying abstract meaning or logical relationship of a sentence","A sentence with many adjectives"], correct:1, explanation:"Chomsky proposed that different 'surface structures' can have the same 'deep structure' (e.g., active vs. passive)." },
  { section:"ling5", q:"What is 'Surface Structure'?", options:["The abstract meaning","The actual realized form of a sentence as spoken or written","The first draft of a sentence"], correct:1, explanation:"This is the outward form of the sentence that we actually see or hear." },
  { section:"ling5", q:"What is 'Structural Ambiguity'?", options:["A sentence with a typo","When a single string of words can be interpreted in multiple ways based on structure","When a word has two meanings"], correct:1, explanation:"Example: 'I saw the man with the telescope' could mean I used a telescope OR the man had one." },
  { section:"ling5", q:"What is 'Immediate Constituent (IC) Analysis'?", options:["Breaking a sentence into its component parts step-by-step","Analyzing a word's meaning","A type of phonetic study"], correct:0, explanation:"We cut a sentence into its two largest parts, then cut those parts, and so on until we reach individual words." },
  { section:"ling5", q:"What is a 'Noun Phrase (NP)'?", options:["A sentence containing only nouns","A phrase with a noun or pronoun as its head","A type of verb"], correct:1, explanation:"Example: 'the big red ball' — 'ball' is the head noun, 'the' and 'big red' are its dependents." },
  { section:"ling5", q:"What is a 'Verb Phrase (VP)'?", options:["A phrase with a verb as its head, including its complements and modifiers","A sentence with two verbs","A list of action words"], correct:0, explanation:"In 'ate the cake quickly', 'ate' is the head verb and the whole group is the VP." },
  { section:"ling5", q:"What is a 'Prepositional Phrase (PP)'?", options:["A phrase beginning with a preposition, followed by an NP","A list of pronouns","A passive sentence"], correct:0, explanation:"Examples: 'in the box', 'under the table', 'before lunch'." },
  { section:"ling5", q:"What is 'Recursion' in syntax?", options:["Repeating the same word twice","The ability of language to embed structures within similar structures infinitely","A type of sentence error"], correct:1, explanation:"'The cat that chased the dog that bit the man that...' — you can keep embedding. This gives language its infinite productivity." },
  { section:"ling5", q:"What is a 'Constituent'?", options:["A grammatical error","A group of words that function as a single unit within a sentence","A type of conjunction"], correct:1, explanation:"You can test constituents with substitution (replace with a pronoun), movement, or deletion." },
  { section:"ling5", q:"What is a 'Passive Construction'?", options:["A sentence with no adjectives","A sentence where the object becomes the grammatical subject (e.g., 'The cake was eaten by her')","A question form"], correct:1, explanation:"Active: 'She ate the cake.' Passive: 'The cake was eaten by her.' Same deep structure, different surface structure." },
  { section:"ling5", q:"What is a 'Head' in a phrase?", options:["The first word in a sentence","The word that determines the type and core meaning of the phrase","The most important sentence"], correct:1, explanation:"In an NP, the head is the noun. In a VP, it's the verb. The head gives the phrase its category label." },
  { section:"ling5", q:"What is a 'Tree Diagram' (parse tree)?", options:["A diagram of a forest","A visual representation of the hierarchical structure of a sentence","A type of flowchart"], correct:1, explanation:"Tree diagrams show how words group into phrases and how phrases combine into sentences." },
  { section:"ling5", q:"What is 'Lexical Ambiguity' (vs. structural ambiguity)?", options:["When a word has two different meanings causing sentence ambiguity","When sentence structure creates two readings","A sentence with too many adjectives"], correct:0, explanation:"'I saw her duck' — 'duck' could be a noun (animal) or verb (crouch). That's lexical, not structural ambiguity." },

  // ── LING6: Semantics ─────────────────────────────────────────────────────
  { section:"ling6", q:"What is Semantics?", options:["The study of word formation","The scientific study of meaning in language","The study of social context"], correct:1, explanation:"Semantics focuses on the literal meaning of words, phrases, and sentences." },
  { section:"ling6", q:"What is 'Polysemy'?", options:["Unrelated words sounding the same","A single word having multiple related meanings (e.g., the 'head' of a person vs. 'head' of a company)","Words with opposite meanings"], correct:1, explanation:"Polysemy involves a conceptual connection between the meanings." },
  { section:"ling6", q:"What is 'Homonymy'?", options:["Words with related meanings","Words that sound or look the same but have unrelated meanings (e.g., 'bat' the animal vs. 'bat' the sports equipment)","Synonyms"], correct:1, explanation:"Homonyms are 'accidental' matches in form with no meaning connection." },
  { section:"ling6", q:"What is 'Hyponymy'?", options:["Relationship between opposites","Relationship of inclusion where a specific word is part of a broader category (e.g., 'rose' is a hyponym of 'flower')","Words that rhyme"], correct:1, explanation:"The broader category is called a 'hypernym'." },
  { section:"ling6", q:"What are 'Synonyms'?", options:["Words with opposite meanings","Words with the same or very similar meanings","Words with the same sounds"], correct:1, explanation:"Examples: 'large' and 'big', 'difficult' and 'hard'." },
  { section:"ling6", q:"What are 'Complementary Antonyms'?", options:["Opposites that have degrees (like hot/cold)","Opposites that are binary with no middle ground (like alive/dead)","Opposites that depend on each other (like buy/sell)"], correct:1, explanation:"In complementary pairs, if you are not one, you MUST be the other." },
  { section:"ling6", q:"What are 'Gradable Antonyms'?", options:["Binary opposites","Opposites along a scale (like big/small or hot/cold) where there are middle points","Relationship between parts of a whole"], correct:1, explanation:"You can be 'somewhat hot' or 'very small'." },
  { section:"ling6", q:"What is a 'Meronym'?", options:["A word that sounds like another","A 'part-of' relationship (e.g., 'wheel' is a meronym of 'car')","A synonym"], correct:1, explanation:"Meronymy describes the relationship between a part and its whole." },
  { section:"ling6", q:"What is 'Denotation'?", options:["The emotional associations of a word","The literal, dictionary meaning of a word","The cultural meaning of a word"], correct:1, explanation:"The denotation of 'snake' is simply 'a reptile without legs'." },
  { section:"ling6", q:"What is 'Connotation'?", options:["The dictionary definition","The emotional, cultural, or implied associations a word carries","The pronunciation of a word"], correct:1, explanation:"'Snake' has connotations of deceit and danger beyond its literal meaning." },
  { section:"ling6", q:"What is 'Entailment'?", options:["A logical consequence where if sentence A is true, sentence B must also be true","Two sentences that contradict each other","A sentence with more than one meaning"], correct:0, explanation:"'She is a widow' entails 'She was married.' You can't be a widow without having been married." },
  { section:"ling6", q:"What is 'Presupposition'?", options:["A conclusion based on evidence","A background assumption that must be true for a sentence to make sense","A type of synonym"], correct:1, explanation:"'John stopped smoking' presupposes that John smoked. The presupposition holds even if you negate it: 'John didn't stop smoking' still presupposes he smoked." },
  { section:"ling6", q:"What is a 'Hypernym' (Superordinate)?", options:["A word with no meaning","The broader category word that includes more specific words (e.g., 'animal' is a hypernym of 'dog')","A word that sounds like another"], correct:1, explanation:"Hypernyms sit above hyponyms in a semantic hierarchy." },
  { section:"ling6", q:"What are 'Relational (Converse) Antonyms'?", options:["Gradable opposites","Pairs where one word implies the other in reverse (e.g., buy/sell, teacher/student, above/below)","Binary complementary pairs"], correct:1, explanation:"If A buys from B, then B sells to A. The relationship is reversed — you can't have one without the other." },
  { section:"ling6", q:"What is 'Semantic Field'?", options:["A region where a language is spoken","A set of words that are all related to the same topic or conceptual area","A type of grammar rule"], correct:1, explanation:"Words like 'scalpel', 'stethoscope', 'diagnosis', and 'prescription' all belong to the semantic field of medicine." },
  { section:"ling6", q:"What is 'Semantic Change'?", options:["Changing your word choice","The way a word's meaning shifts over time","Translating between languages"], correct:1, explanation:"'Nice' used to mean 'foolish' in Middle English. 'Awful' meant 'inspiring awe'. Meanings shift!" },
  { section:"ling6", q:"What is 'Amelioration' in semantic change?", options:["When a word's meaning becomes more negative over time","When a word's meaning becomes more positive or elevated over time","When a word disappears from use"], correct:1, explanation:"'Knight' originally meant 'boy' or 'servant' and ameliorated to mean a noble warrior." },
  { section:"ling6", q:"What is 'Pejoration' in semantic change?", options:["When a word gains a positive meaning","When a word's meaning becomes more negative over time","When a word's meaning expands"], correct:1, explanation:"'Villain' originally meant 'farm worker' and pejerated to mean 'evil person'." },

  // ── LING7: Pragmatics ────────────────────────────────────────────────────
  { section:"ling7", q:"What is Pragmatics?", options:["The study of grammar","The study of how context contributes to meaning","The study of word roots"], correct:1, explanation:"Pragmatics looks at the 'invisible' meaning—what a speaker intends vs. what they literally say." },
  { section:"ling7", q:"What is a 'Speech Act'?", options:["An actor's lines","An utterance that performs a function or action (e.g., promising, ordering, apologizing)","A loud noise"], correct:1, explanation:"Speech act theory (Austin/Searle) says language is not just for describing, but for DOING." },
  { section:"ling7", q:"What are Grice's Maxims?", options:["Four rules for good writing","Four conversational maxims (Quantity, Quality, Relation, Manner) that facilitate cooperation","Rules for pronunciation"], correct:1, explanation:"Grice argued that speakers generally try to be helpful and relevant in conversation." },
  { section:"ling7", q:"What is 'Flouting' a maxim?", options:["Following the rules perfectly","Deliberately breaking a maxim to imply a hidden meaning (implicature)","Ignoring a speaker"], correct:1, explanation:"If someone asks 'Is he smart?' and you say 'He has a nice personality,' you are flouting the maxim of relation to imply 'no'." },
  { section:"ling7", q:"What is 'Deixis'?", options:["A type of grammatical error","Words whose meaning depends entirely on context (like 'here', 'there', 'me', 'tomorrow')","A type of vowel"], correct:1, explanation:"Deictic words 'point' to people, places, or times that only make sense if you know the context." },
  { section:"ling7", q:"What is 'Positive Face' in politeness theory?", options:["Wanting to be alone","The desire to be liked, appreciated, and approved of by others","Having a happy expression"], correct:1, explanation:"Positive politeness strategies include giving compliments or showing interest." },
  { section:"ling7", q:"What is 'Negative Face'?", options:["Being rude to people","The desire to be independent, have freedom of action, and not be imposed upon","Being sad"], correct:1, explanation:"Negative politeness involves apologizing for an intrusion or being indirect (e.g., 'I hate to ask, but...')." },
  { section:"ling7", q:"Who developed the theory of Speech Acts?", options:["Saussure and Chomsky","Austin and Searle","Grice and Labov"], correct:1, explanation:"J.L. Austin introduced the concept in 'How to Do Things with Words' (1962), and Searle further developed it." },
  { section:"ling7", q:"What is a 'Locutionary Act'?", options:["The implied meaning of an utterance","The literal act of saying something with a specific meaning","The effect an utterance has on the listener"], correct:1, explanation:"It's simply the act of producing a meaningful utterance — the 'what was said'." },
  { section:"ling7", q:"What is an 'Illocutionary Act'?", options:["The literal meaning of words","The intended function or purpose behind an utterance (e.g., a warning, request, or promise)","The physical act of speaking"], correct:1, explanation:"'It's cold in here' as an illocutionary act might be a request to close the window." },
  { section:"ling7", q:"What is a 'Perlocutionary Act'?", options:["The social status of a speaker","The actual effect or consequence the utterance has on the listener","The grammar of a statement"], correct:1, explanation:"If someone says 'It's cold' and you close the window, that closing is the perlocutionary effect." },
  { section:"ling7", q:"What is 'Conversational Implicature'?", options:["What is literally said","What is implied or inferred beyond what is literally said, based on conversational norms","A type of insult"], correct:1, explanation:"When asked 'Did you eat all the cake?' you respond 'I was very hungry.' The implicature is yes." },
  { section:"ling7", q:"What is the Maxim of Quantity?", options:["Use complex vocabulary","Say neither more nor less than is required","Always speak loudly and clearly"], correct:1, explanation:"Don't be too brief (leaving out needed info) or too wordy (adding unnecessary info)." },
  { section:"ling7", q:"What is the Maxim of Quality?", options:["Speak in a high-quality accent","Only say what you believe to be true and have evidence for","Use the best words"], correct:1, explanation:"Don't lie or say things you don't have evidence for." },
  { section:"ling7", q:"What is the Maxim of Relation (Relevance)?", options:["Say everything relevant to a topic","Be relevant — make your contribution pertain to the current topic of conversation","Only speak when spoken to"], correct:1, explanation:"Don't bring up unrelated topics mid-conversation. If someone asks the time and you mention the weather, you've violated this maxim." },
  { section:"ling7", q:"What is the Maxim of Manner?", options:["Speak with good manners","Be clear, brief, orderly, and avoid ambiguity","Use formal language always"], correct:1, explanation:"Avoid obscure expressions, ambiguity; be brief and orderly." },
  { section:"ling7", q:"Who developed Brown and Levinson's Politeness Theory?", options:["Austin and Searle","Grice","Penelope Brown and Stephen Levinson"], correct:2, explanation:"They proposed that politeness is a rational strategy to manage 'face' — our public self-image." },
  { section:"ling7", q:"What is a 'Face Threatening Act (FTA)'?", options:["An aggressive facial expression","An utterance that threatens someone's positive or negative face (e.g., a direct order or criticism)","A compliment"], correct:1, explanation:"Requests inherently threaten negative face (your autonomy). Criticisms threaten positive face (your self-image)." },

  // ── LING8: Sociolinguistics ──────────────────────────────────────────────
  { section:"ling8", q:"What is Sociolinguistics?", options:["The study of language in the brain","The study of how language varies and changes based on social factors (class, gender, age, etc.)","The study of ancient scripts"], correct:1, explanation:"Sociolinguistics examines the relationship between language and society." },
  { section:"ling8", q:"What is a 'Sociolect'?", options:["A regional variety of language","A variety of language associated with a particular social class or group","A secret code"], correct:1, explanation:"Differences in speech between social classes are sociolectal." },
  { section:"ling8", q:"What is 'Code-switching'?", options:["Changing your password","Alternating between two or more languages or dialects in a single conversation","Learning a new language"], correct:1, explanation:"It is a common phenomenon in multilingual communities." },
  { section:"ling8", q:"What is 'Diglossia'?", options:["Speaking two languages","When a community uses two distinct varieties of a language for different social functions (High vs. Low)","A speech impediment"], correct:1, explanation:"For example, using Standard Arabic for news but a local dialect at home." },
  { section:"ling8", q:"What is 'Register'?", options:["A list of names","Language variety used in specific professional or situational contexts (e.g., 'legalese' or 'medicalese')","The speed of speech"], correct:1, explanation:"Register depends on the 'field' (topic), 'tenor' (relationship), and 'mode' (spoken/written)." },
  { section:"ling8", q:"What is an 'Isogloss'?", options:["A type of frozen language","A line on a map marking the boundary of a specific linguistic feature","A word with no meaning"], correct:1, explanation:"Isoglosses are used in dialectology to show where people say 'pail' vs. 'bucket'." },
  { section:"ling8", q:"What is a 'Dialect'?", options:["A wrong way of speaking","A regional or social variety of a language with distinct vocabulary, grammar, and pronunciation","A foreign language"], correct:1, explanation:"All speakers speak a dialect — 'Standard English' is itself a dialect, just one with overt prestige." },
  { section:"ling8", q:"What is 'Language Variation'?", options:["Errors in grammar","The natural differences in how language is used across groups, regions, and situations","The evolution of a language over centuries"], correct:1, explanation:"Variation occurs at all levels: phonological, lexical, and grammatical." },
  { section:"ling8", q:"What is 'Idiolect'?", options:["A shared group dialect","An individual person's unique way of speaking","A language spoken by a small tribe"], correct:1, explanation:"Your idiolect is the sum total of your personal linguistic habits — your unique fingerprint in language." },
  { section:"ling8", q:"Who is William Labov known for in sociolinguistics?", options:["Inventing the IPA","Pioneering quantitative sociolinguistics and studying African American Vernacular English (AAVE)","Translating the Bible"], correct:1, explanation:"Labov's New York department store study (1966) was groundbreaking — he showed that /r/ pronunciation correlated with social class." },
  { section:"ling8", q:"What is 'Language Attitude'?", options:["Being rude in conversation","People's beliefs and feelings about languages or dialects and their speakers","A formal style of writing"], correct:1, explanation:"Attitudes toward dialects often reflect social prejudice more than linguistic 'correctness'." },
  { section:"ling8", q:"What is 'Accommodation Theory'?", options:["Speaking while sleeping","The tendency for speakers to adjust their speech style toward (convergence) or away from (divergence) their interlocutor","A theory about hotel bookings"], correct:1, explanation:"We converge to build rapport and diverge to assert identity." },
  { section:"ling8", q:"What is 'Linguistic Relativity' (Sapir-Whorf Hypothesis)?", options:["All languages are the same","The idea that the language you speak influences (or determines) how you think and perceive the world","A theory of language evolution"], correct:1, explanation:"The strong version (Whorfian determinism) says language determines thought. The weak version says language influences thought." },
  { section:"ling8", q:"What is 'Language Planning'?", options:["Planning a conversation","Deliberate efforts by governments or authorities to influence or change a language's status, form, or use","Writing a language textbook"], correct:1, explanation:"Language planning involves status planning (which language is official), corpus planning (standardizing grammar/spelling), and acquisition planning (education policy)." },
  { section:"ling8", q:"What is 'Ethnolect'?", options:["An ethnic insult","A variety of language associated with a particular ethnic group","An extinct language"], correct:1, explanation:"African American Vernacular English (AAVE) and Chicano English are examples of ethnolects." },

  // ── LING9: Psycholinguistics ─────────────────────────────────────────────
  { section:"ling9", q:"What is Psycholinguistics?", options:["The study of crazy people","The study of the mental processes and representations involved in language use","The study of animal communication"], correct:1, explanation:"It combines psychology and linguistics to see how the brain handles language." },
  { section:"ling9", q:"Where is 'Broca's Area' located?", options:["Temporal lobe","Frontal lobe (usually on the left)","Brain stem"], correct:1, explanation:"It is primarily responsible for speech production and grammar." },
  { section:"ling9", q:"Where is 'Wernicke's Area' located?", options:["Frontal lobe","Temporal lobe (usually on the left)","Occipital lobe"], correct:1, explanation:"It is primarily responsible for language comprehension and word meaning." },
  { section:"ling9", q:"What is 'Aphasia'?", options:["A memory loss condition","An acquired language disorder caused by brain damage","A type of stuttering"], correct:1, explanation:"Broca's and Wernicke's aphasias are the most common types." },
  { section:"ling9", q:"What is a 'Spoonerism'?", options:["Eating with a spoon","A speech error where sounds are swapped between words (e.g., 'lighting a fire' → 'fighting a liar')","A type of rhyming slang"], correct:1, explanation:"Named after William Spooner, these errors provide clues about how we plan speech." },
  { section:"ling9", q:"What is 'Lateralization'?", options:["Moving side-to-side","The specialization of language functions to one hemisphere of the brain","Growing taller"], correct:1, explanation:"For most people, language is lateralized to the left hemisphere." },
  { section:"ling9", q:"What is 'Broca's Aphasia'?", options:["Loss of ability to understand language","Difficulty with speech production — speech is slow, effortful, and telegraphic but comprehension is mostly intact","Complete loss of all language ability"], correct:1, explanation:"A person with Broca's aphasia might say 'Walk dog' instead of 'I walked the dog.' They know what they want to say but struggle to produce it." },
  { section:"ling9", q:"What is 'Wernicke's Aphasia'?", options:["Inability to produce speech","Fluent but meaningless or confused speech, with poor comprehension","A reading disorder only"], correct:1, explanation:"Wernicke's aphasics speak fluently but what they say is often nonsensical ('word salad')." },
  { section:"ling9", q:"What is the 'Lexical Access' process?", options:["Looking up words in a dictionary","The mental process by which we retrieve words from our mental lexicon during speech or reading","A type of memory test"], correct:1, explanation:"Models of lexical access (like cohort model or TRACE) explain how we recognize and retrieve words so quickly." },
  { section:"ling9", q:"What is the 'Garden Path Effect'?", options:["A pleasant walk affecting language","When a reader initially misparses a sentence and must revise their interpretation","A type of metaphor"], correct:1, explanation:"'The horse raced past the barn fell.' We expect 'raced' to be the main verb but must reanalyze it as a reduced relative clause." },
  { section:"ling9", q:"What is 'Mental Lexicon'?", options:["A physical dictionary","The internal 'dictionary' in our mind containing all the words we know, including their sounds, meanings, and grammar","A list of words we dislike"], correct:1, explanation:"The mental lexicon is not alphabetical — words are linked by sound, meaning, and association." },
  { section:"ling9", q:"What is a 'Tip-of-the-Tongue (TOT) State'?", options:["Burning your tongue","The feeling of knowing a word but being temporarily unable to retrieve it","Speaking too fast"], correct:1, explanation:"TOT states show that word meaning and word form are stored and retrieved separately in the mental lexicon." },
  { section:"ling9", q:"What is 'Priming' in psycholinguistics?", options:["Starting to speak","The phenomenon where exposure to one word makes processing a related word faster","Memorizing vocabulary"], correct:1, explanation:"Hearing 'doctor' makes you recognize 'nurse' faster because they are semantically related." },
  { section:"ling9", q:"What is 'Prosody'?", options:["A type of poem","The rhythmic and melodic aspects of speech (stress, rhythm, intonation)","A grammatical error"], correct:1, explanation:"Prosody carries meaning beyond the words. The same sentence said with different prosody can mean different things." },

  // ── LING10: Language Acquisition ─────────────────────────────────────────
  { section:"ling10", q:"What is 'First Language Acquisition'?", options:["Learning a language at school","The natural process by which children learn their native language","Translating a book"], correct:1, explanation:"This happens without formal teaching during the 'critical period'." },
  { section:"ling10", q:"What is the 'Holophrastic Stage'?", options:["Cooing and babbling","When a child uses a single word to express a complex idea (e.g., 'Juice!' = 'I want juice!')","Learning to read"], correct:1, explanation:"This usually happens around 12-18 months of age." },
  { section:"ling10", q:"What is 'Telegraphic Speech'?", options:["Sending a telegram","Speech that lacks functional words and contains only essential content words (e.g., 'Daddy go car')","Using codes"], correct:1, explanation:"This stage follows the two-word stage, usually around age 2." },
  { section:"ling10", q:"What is 'Overgeneralization'?", options:["Thinking everyone is the same","When children apply a grammar rule too broadly (e.g., saying 'goed' instead of 'went')","Being too loud"], correct:1, explanation:"This proves children are learning rules, not just imitating adults." },
  { section:"ling10", q:"What is the 'Affective Filter' in Krashen's theory?", options:["A filter for bad words","A mental block (anxiety, low motivation) that prevents language acquisition","A part of the ear"], correct:1, explanation:"A high filter (stress) stops the 'input' from reaching the 'acquisition' part of the brain." },
  { section:"ling10", q:"What is the 'Babbling Stage'?", options:["The stage where children learn to write","Around 6-8 months, when infants produce consonant-vowel syllables (ba-ba-ba, ma-ma)","When children use two-word sentences"], correct:1, explanation:"Babbling is universal across all cultures and even deaf children start babbling in sign language." },
  { section:"ling10", q:"What is the 'Two-Word Stage'?", options:["Using complete sentences","Around 18-24 months, children combine two words to express basic relations (e.g., 'more milk', 'daddy gone')","When a child knows two languages"], correct:1, explanation:"This stage shows children are beginning to understand syntax — they know order matters ('daddy go' not 'go daddy' when they mean daddy left)." },
  { section:"ling10", q:"What is Krashen's 'Input Hypothesis'?", options:["The more you speak, the more you learn","Acquisition happens when learners are exposed to language slightly beyond their current level (i+1)","Learning grammar rules is the best way to acquire language"], correct:1, explanation:"'i' = current level, '+1' = slightly above. Too easy = boring, too hard = incomprehensible. The sweet spot drives acquisition." },
  { section:"ling10", q:"What is the 'Monitor Hypothesis' in Krashen's theory?", options:["Watching TV to learn language","Consciously learned grammar rules act as an editor (monitor) on output produced by the acquired system","Following a mentor's speech"], correct:1, explanation:"The Monitor only works when you have time, focus on form, and know the rule. In normal conversation, the acquired system takes over." },
  { section:"ling10", q:"What is 'Interlanguage'?", options:["A language between two countries","The intermediate linguistic system a learner develops while acquiring a second language","A type of pidgin"], correct:1, explanation:"Selinker (1972) coined this. Interlanguage has features of L1, L2, and rules unique to the learner's current state." },
  { section:"ling10", q:"What is 'Fossilization' in L2 acquisition?", options:["A language dying out","When certain errors in a learner's interlanguage become permanent and stop developing","Learning too slowly"], correct:1, explanation:"Many advanced L2 speakers retain a foreign accent or specific grammatical errors despite years of exposure." },
  { section:"ling10", q:"What is 'Child-Directed Speech' (CDS / Motherese)?", options:["Books written for children","The simplified, high-pitched, repetitive speech adults use when talking to infants","Teaching a child to read"], correct:1, explanation:"CDS features short sentences, simple vocabulary, exaggerated intonation, and frequent repetition." },
  { section:"ling10", q:"What is the 'Cooing Stage' in language development?", options:["The stage where children write first words","Around 2-3 months, when infants produce soft vowel-like sounds","When babbling starts"], correct:1, explanation:"Cooing precedes babbling and is the infant's first vocal exploration beyond crying." },
  { section:"ling10", q:"What is 'Transfer' (Interference) in L2 learning?", options:["Translating a book","When features of a learner's first language influence their second language (can be positive or negative)","Copying from a classmate"], correct:1, explanation:"A Spanish speaker might say 'I have 20 years' (Tengo 20 años) in English — negative transfer from L1 structure." },

  // ── LING11: Pidgins, Creoles & Standardization ───────────────────────────
  { section:"ling11", q:"What is a 'Pidgin'?", options:["A type of bird","A simplified, unstable contact language with no native speakers","A dead language"], correct:1, explanation:"Pidgins develop for basic communication between groups with different languages." },
  { section:"ling11", q:"What is a 'Creole'?", options:["A type of spicy food","A stable language that developed from a pidgin and has native speakers","A dialect of French only"], correct:1, explanation:"Creolization happens when children are born into a pidgin-speaking environment." },
  { section:"ling11", q:"What is 'Language Standardization'?", options:["Making language difficult","The process of choosing and codifying one variety of a language as the official 'correct' form","Removing all slang"], correct:1, explanation:"Standardization involves dictionaries, grammars, and use in education/government." },
  { section:"ling11", q:"What is 'Overt Prestige'?", options:["Being cool in a gang","Status attached to speaking the standard, high-status variety of a language","Using lots of slang"], correct:1, explanation:"Overt prestige is usually associated with education and professional success." },
  { section:"ling11", q:"What is 'Covert Prestige'?", options:["Status attached to non-standard varieties or dialects within specific social groups (e.g., sounding 'tough' or 'authentic')","A hidden dictionary","Using a fake accent"], correct:0, explanation:"Covert prestige explains why non-standard dialects persist even when stigmatized." },
  { section:"ling11", q:"What triggers Creolization?", options:["A government decision","When children grow up in a pidgin-speaking community and acquire it as a native language, expanding it","Two countries merging"], correct:1, explanation:"The children's innate language faculty fills in the gaps in pidgin grammar, creating a fully-fledged language." },
  { section:"ling11", q:"What is 'Language Death'?", options:["A language being banned","When a language has no more native speakers, usually due to speakers shifting to a dominant language","Forgetting a language"], correct:1, explanation:"Currently, a language dies approximately every two weeks. Many indigenous languages are endangered." },
  { section:"ling11", q:"What is 'Language Shift'?", options:["Moving to a new country","The process by which a community gradually stops using one language in favor of another","Changing an accent"], correct:1, explanation:"Communities often shift to the dominant or more prestigious language over generations." },
  { section:"ling11", q:"What is a 'Lingua Franca'?", options:["The French language","A language used as a common means of communication between speakers of different native languages","A type of creole only"], correct:1, explanation:"English functions as the global lingua franca today. Swahili is a lingua franca in East Africa." },
  { section:"ling11", q:"What is 'Corpus Planning'?", options:["Making a body of texts","Deliberate efforts to change or standardize the form of a language (spelling, grammar, vocabulary)","Planning a library"], correct:1, explanation:"Developing a standard spelling system or creating new technical vocabulary for a language are corpus planning activities." },
  { section:"ling11", q:"What is 'Status Planning'?", options:["Improving your social status","Deciding which language(s) get official status or recognition in a country","Planning a census"], correct:1, explanation:"Choosing English as an official language of government in a multilingual country is status planning." },
  { section:"ling11", q:"What is a 'Contact Language'?", options:["A language used to call people","Any language (including pidgins and creoles) that emerges from contact between two linguistic communities","A telephone language"], correct:1, explanation:"Contact languages develop when groups who don't share a language need to communicate." },
  { section:"ling11", q:"What is 'Linguistic Imperialism'?", options:["An emperor who speaks many languages","The dominance of one language over others due to political, economic, or cultural power","Teaching grammar in schools"], correct:1, explanation:"Robert Phillipson coined this term — the spread of English globally, often at the expense of local languages, is a key example." },
  { section:"ling11", q:"What is 'Language Revitalization'?", options:["Making a language sound more exciting","Efforts to restore or increase the use of an endangered or dormant language","Publishing new dictionaries"], correct:1, explanation:"Hebrew was successfully revived from a dormant literary language to a living vernacular in Israel. Welsh is another ongoing revitalization example." },

  // ── LING12: Cheatsheet / Final Review ────────────────────────────────────
  { section:"ling12", q:"Which level of linguistics studies SENTENCE structure?", options:["Morphology","Syntax","Semantics"], correct:1, explanation:"Syntax = Sentence rules." },
  { section:"ling12", q:"Which level studies WORD structure?", options:["Phonology","Morphology","Pragmatics"], correct:1, explanation:"Morphology = Morphemes/Words." },
  { section:"ling12", q:"Which level studies MEANING?", options:["Syntax","Phonetics","Semantics"], correct:2, explanation:"Semantics = Meaning." },
  { section:"ling12", q:"Which level studies CONTEXTUAL meaning?", options:["Semantics","Pragmatics","Sociolinguistics"], correct:1, explanation:"Pragmatics = Meaning in use/context." },
  { section:"ling12", q:"What is the smallest unit of sound that changes meaning?", options:["Morpheme","Phoneme","Allophone"], correct:1, explanation:"Phoneme." },
  { section:"ling12", q:"What is the smallest unit of meaning?", options:["Word","Morpheme","Phoneme"], correct:1, explanation:"Morpheme." },
  { section:"ling12", q:"Saussure's Signifier + Signified = ?", options:["A grammar rule","A linguistic sign","A phoneme"], correct:1, explanation:"The Signifier (form) + Signified (concept) together make the Linguistic Sign." },
  { section:"ling12", q:"Langue is to Parole as Competence is to ___?", options:["Performance","Phoneme","Morpheme"], correct:0, explanation:"Saussure: Langue/Parole. Chomsky: Competence/Performance. Both distinguish knowledge from use." },
  { section:"ling12", q:"Which area of the brain is responsible for speech PRODUCTION?", options:["Wernicke's Area","Broca's Area","Occipital Lobe"], correct:1, explanation:"Broca's Area (frontal lobe) = production. Wernicke's Area (temporal lobe) = comprehension." },
  { section:"ling12", q:"Which area is responsible for language COMPREHENSION?", options:["Broca's Area","Wernicke's Area","Cerebellum"], correct:1, explanation:"Wernicke's Area processes incoming language." },
  { section:"ling12", q:"'Smog' is an example of what word formation process?", options:["Clipping","Blending","Back-formation"], correct:1, explanation:"Smog = Smoke + Fog. Parts of two words are merged = Blending." },
  { section:"ling12", q:"'Prof' (from professor) is an example of what?", options:["Blending","Acronym","Clipping"], correct:2, explanation:"Clipping = shortening a word. Prof, math, ad, lab." },
  { section:"ling12", q:"The 'p' in 'pin' vs. the 'p' in 'spin' are examples of ___?", options:["Minimal Pairs","Allophones","Phonemes"], correct:1, explanation:"They are both realizations of /p/ but in different environments — allophones." },
  { section:"ling12", q:"'Can you pass the salt?' is literally a question but functions as a ___?", options:["A minimal pair","An indirect speech act (a request)","A complementary antonym"], correct:1, explanation:"The illocutionary force is a request, not a genuine inquiry about ability. This is a classic indirect speech act." },
  { section:"ling12", q:"'Rose' is a ___ of 'flower'.", options:["Hypernym","Hyponym","Meronym"], correct:1, explanation:"Rose is more specific than flower → Rose is a hyponym of flower." },
  { section:"ling12", q:"The relationship between 'wheel' and 'car' is called ___.", options:["Hyponymy","Synonymy","Meronymy"], correct:2, explanation:"Wheel is a PART of a car → Meronymy (part-whole relationship)." },
  { section:"ling12", q:"What type of antonyms are 'alive' and 'dead'?", options:["Gradable Antonyms","Complementary Antonyms","Relational Antonyms"], correct:1, explanation:"Binary, no middle ground. You can't be 'somewhat alive'." },
  { section:"ling12", q:"What type of antonyms are 'hot' and 'cold'?", options:["Gradable Antonyms","Complementary Antonyms","Converse Antonyms"], correct:0, explanation:"There is a scale in between: warm, cool, lukewarm." },
  { section:"ling12", q:"Which theory says children learn language via imitation and reward?", options:["Nativism","Behaviorism","Interactionism"], correct:1, explanation:"B.F. Skinner's Behaviorism. Chomsky refuted this with his review of Skinner's 'Verbal Behavior'." },
  { section:"ling12", q:"What is the difference between Phonetics and Phonology?", options:["They are the same thing","Phonetics = physical sounds; Phonology = how sounds function in a language system","Phonology studies writing; Phonetics studies speech"], correct:1, explanation:"Phonetics is universal (any human sound); Phonology is language-specific (how sounds contrast in a particular language)." },

  // ── Extra Coverage: +1 question per topic (ling1–ling12) ───────────────
  { section:"ling1", q:"Which pair correctly matches scholar and concept?", options:["Saussure—Language Acquisition Device","Chomsky—Universal Grammar","Skinner—Langue/Parole"], correct:1, explanation:"Universal Grammar is Chomsky's core proposal; Langue/Parole belongs to Saussure." },
  { section:"ling1", q:"Saussure's synchronic approach is best described as:", options:["Tracing language from Latin to modern forms","Analyzing language as a system at one time point","Comparing unrelated language families only"], correct:1, explanation:"Synchronic analysis studies a language state at a specific moment." },
  { section:"ling1", q:"Which claim aligns with Chomsky's view of productivity?", options:["Speakers only repeat memorized sentences","Finite rules can generate infinitely many sentences","Language is entirely imitation-based"], correct:1, explanation:"Generative grammar explains creative sentence production." },
  { section:"ling1", q:"'Dog' in English and 'chien' in French illustrate:", options:["Natural sign relation","Arbitrariness of the sign","Phonetic universality"], correct:1, explanation:"No inherent natural link binds a concept to a specific word form." },
  { section:"ling2", q:"Which branch of phonetics studies the frequencies and amplitudes of speech sounds?", options:["Articulatory phonetics","Acoustic phonetics","Auditory phonetics"], correct:1, explanation:"Acoustic phonetics analyzes speech as measurable sound waves." },
  { section:"ling2", q:"Which pair is both voiceless plosives in English?", options:["/b/ and /d/","/p/ and /t/","/m/ and /n/"], correct:1, explanation:"/p/ and /t/ are voiceless oral stops." },
  { section:"ling2", q:"What primarily distinguishes /f/ from /v/?", options:["Place of articulation","Voicing","Nasal airflow"], correct:1, explanation:"They share place/manner but differ in voicing." },
  { section:"ling2", q:"The sound /ŋ/ in 'sing' is a:", options:["Bilabial plosive","Velar nasal","Alveolar fricative"], correct:1, explanation:"/ŋ/ is produced at the velum with nasal airflow." },
  { section:"ling3", q:"Why are minimal pairs important in phonology?", options:["They prove two sounds are allophones","They show two sounds contrast in meaning and are separate phonemes","They show stress patterns only"], correct:1, explanation:"If swapping one sound changes meaning, the sounds are separate phonemes." },
  { section:"ling3", q:"In English, aspirated [pʰ] in 'pin' and unaspirated [p] in 'spin' are:", options:["Different phonemes","Allophones of /p/","Separate morphemes"], correct:1, explanation:"They are context-conditioned variants of one phoneme." },
  { section:"ling3", q:"Which concept restricts allowable sound combinations in a language?", options:["Hyponymy","Phonotactics","Entailment"], correct:1, explanation:"Phonotactics defines legal sound sequencing patterns." },
  { section:"ling3", q:"A falling pitch at sentence end in English most often signals:", options:["Plural marking","Statement intonation","Past tense"], correct:1, explanation:"Intonation patterns help mark communicative function." },
  { section:"ling4", q:"Which of the following contains exactly one free morpheme plus one bound morpheme?", options:["cats","bookstore","unhappy"], correct:0, explanation:"'cat' is free and plural '-s' is bound." },
  { section:"ling4", q:"Which word is formed by prefixation?", options:["teacher","redo","smog"], correct:1, explanation:"'re-' + 'do' is prefixation." },
  { section:"ling4", q:"'Brunch' is an example of:", options:["Compounding","Blending","Clipping"], correct:1, explanation:"It blends parts of breakfast + lunch." },
  { section:"ling4", q:"The suffix '-ness' in 'kindness' primarily creates a:", options:["Verb","Noun","Adjective"], correct:1, explanation:"-ness typically nominalizes adjectives." },
  { section:"ling5", q:"In syntax, what does 'recursion' mainly refer to?", options:["Repeating letters for emphasis","Embedding structures of the same type inside each other","Memorizing sentence templates"], correct:1, explanation:"Recursion allows potentially infinite sentence generation." },
  { section:"ling5", q:"In the clause 'the student who won', 'who won' functions as a:", options:["Main clause","Relative clause","Prepositional phrase"], correct:1, explanation:"It modifies 'student' as a relative clause." },
  { section:"ling5", q:"Which word order is canonical in English declaratives?", options:["SOV","VSO","SVO"], correct:2, explanation:"English usually follows Subject-Verb-Object order." },
  { section:"ling5", q:"Which sentence is grammatical in standard English?", options:["She don't like tea.","She doesn't like tea.","She not like tea."], correct:1, explanation:"Agreement and auxiliary usage are correct in option 2." },
  { section:"ling6", q:"Which relation is shown by 'big' and 'large'?", options:["Antonymy","Synonymy","Meronymy"], correct:1, explanation:"They have similar meanings, so this is synonymy." },
  { section:"ling6", q:"'Vehicle' is a _____ of 'car'.", options:["Hyponym","Hypernym","Meronym"], correct:1, explanation:"Vehicle is the broader superclass term." },
  { section:"ling6", q:"'Buy' and 'sell' are best classified as:", options:["Complementary antonyms","Converse/relational antonyms","Homophones"], correct:1, explanation:"They describe the same transaction from opposite roles." },
  { section:"ling6", q:"A sentence that's grammatical but nonsensical mainly shows a split between:", options:["Syntax and semantics","Phonetics and orthography","Pragmatics and morphology"], correct:0, explanation:"Form can be well-formed even when meaning is odd." },
  { section:"ling7", q:"If someone says 'It's cold in here' to request a closed window, this is mainly:", options:["A direct speech act","An indirect speech act","A semantic anomaly"], correct:1, explanation:"The literal statement performs a request via context." },
  { section:"ling7", q:"The literal dictionary meaning of a sentence corresponds most to:", options:["Illocution","Locution","Perlocution"], correct:1, explanation:"Locutionary meaning is the literal propositional content." },
  { section:"ling7", q:"Saying 'Could you pass the salt?' usually performs which act?", options:["Request","Promise","Apology"], correct:0, explanation:"It conventionally functions as a polite request." },
  { section:"ling7", q:"'Some students passed' may implicate 'not all' due to:", options:["Scalar implicature","Metathesis","Allophony"], correct:0, explanation:"Pragmatic inference on informational scale terms." },
  { section:"ling8", q:"Which term describes language variation based on region?", options:["Idiolect","Dialect","Register"], correct:1, explanation:"Dialect is region/social variety; idiolect is individual speech style." },
  { section:"ling8", q:"Language style that shifts by situation/formality is called:", options:["Register","Pidgin","Creole"], correct:0, explanation:"Register varies across context and audience." },
  { section:"ling8", q:"Frequent switching between two languages within interaction is:", options:["Elision","Code-switching","Back-formation"], correct:1, explanation:"Code-switching is common in multilingual communities." },
  { section:"ling8", q:"Labov's department store study is famous for studying:", options:["Syntax trees","Social stratification of /r/ pronunciation","Child language stages"], correct:1, explanation:"He linked pronunciation patterns to social class." },
  { section:"ling9", q:"Damage to Broca's area most strongly affects:", options:["Speech production fluency","Visual processing","Hearing pitch"], correct:0, explanation:"Broca's aphasia is characterized by effortful, non-fluent output." },
  { section:"ling9", q:"Fluent but semantically empty speech is most typical of:", options:["Broca's aphasia","Wernicke's aphasia","Dysgraphia"], correct:1, explanation:"Wernicke's aphasia impairs comprehension and semantic coherence." },
  { section:"ling9", q:"A temporary failure to retrieve a known word is a:", options:["Garden-path sentence","Tip-of-the-tongue state","Minimal pair"], correct:1, explanation:"TOT reveals partial lexical activation." },
  { section:"ling9", q:"Most right-handed speakers show dominant language lateralization in the:", options:["Left hemisphere","Right hemisphere","Cerebellum"], correct:0, explanation:"Language functions are typically left-lateralized." },
  { section:"ling10", q:"A child saying 'mouses' instead of 'mice' is evidence of:", options:["Imitation only","Overgeneralization","Code-switching"], correct:1, explanation:"The child applies a productive plural rule too broadly." },
  { section:"ling10", q:"The one-word stage in child language is called:", options:["Telegraphic stage","Holophrastic stage","Babbling stage"], correct:1, explanation:"Single words express full propositions at this stage." },
  { section:"ling10", q:"Krashen's i+1 emphasizes input that is:", options:["Far beyond learner level","Slightly above current competence","Only grammar drills"], correct:1, explanation:"Comprehensible challenge supports acquisition." },
  { section:"ling10", q:"Influence of L1 on L2 learning is commonly called:", options:["Transfer","Assimilation","Accommodation"], correct:0, explanation:"Transfer can be positive or negative." },
  { section:"ling11", q:"Which statement best describes a pidgin?", options:["A fully developed first language","A contact code with reduced grammar and no native speakers initially","A standard national language"], correct:1, explanation:"Pidgins emerge for communication across language groups without shared L1." },
  { section:"ling11", q:"A pidgin becomes a creole when:", options:["Government bans it","Children acquire it as a native language","It loses vocabulary"], correct:1, explanation:"Nativization expands/stabilizes the system." },
  { section:"ling11", q:"Choosing an official language for administration is:", options:["Corpus planning","Status planning","Phonological planning"], correct:1, explanation:"Status planning concerns societal function and recognition." },
  { section:"ling11", q:"Efforts to restore endangered languages are called:", options:["Language revitalization","Language erosion","Language reduction"], correct:0, explanation:"Revitalization includes policy, education, and community action." },
  { section:"ling12", q:"Which field studies language meaning in social context rather than literal meaning alone?", options:["Semantics","Pragmatics","Phonetics"], correct:1, explanation:"Pragmatics focuses on speaker meaning in context." },
  { section:"ling12", q:"Smallest meaningful unit in language is:", options:["Phoneme","Morpheme","Syllable"], correct:1, explanation:"Morpheme carries meaning/function." },
  { section:"ling12", q:"Broca's area is primarily linked to:", options:["Speech production","Visual parsing","Auditory localization"], correct:0, explanation:"It supports planning/production of language output." },
  { section:"ling12", q:"Phonology differs from phonetics because it studies:", options:["Any physical speech sound","Sound patterns within a language system","Only spelling systems"], correct:1, explanation:"Phonology is language-specific and rule-based." },
];
